import {IonRippleEffect,IonIcon} from '@ionic/react';
import Link, {ThLink} from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
const _not_found = {title: "Unknown", jsx: <><h2 id="ragepower-not_found-error">Error</h2>
<p>Unable to find the requested rage power.</p>
</>};
const _animal_fury = {title: "Animal Fury", jsx: <><p>While raging, the barbarian gains a bite attack. If used as part of a full attack action, the bite attack is made at the barbarian's full base attack bonus -5. If the bite hits, it deals 1d4 points of damage (assuming the barbarian is Medium; 1d3 points of damage if Small) plus half the barbarian's Strength modifier. A barbarian can make a bite attack as part of the action to maintain or break free from a grapple. This attack is resolved before the grapple check is made. If the bite attack hits, any grapple checks made by the barbarian against the target this round are at a +2 bonus.</p>
</>};
const _greater_animal_fury = {title: "Greater Animal Fury", jsx: <><p>This power works as animal fury, but the barbarian's bite attack deals damage as if she were <Link to="/misc/one_size_category_larger">one size category larger</Link>. A barbarian must have the <Link to="/ragepower/animal_fury">animal fury</Link> rage power to select this rage power.</p>
</>};
const _bloody_bite = {title: "Bloody Bite", jsx: <><p>This rage power is available to <Link to="/race/half_orc">half-orc</Link> barbarians. The barbarian's bite attack deals 1d6 points of bleed damage in addition to its other effects. The barbarian must have the <Link to="/ragepower/animal_fury">animal fury</Link> rage power or a natural bite attack before selecting this power.</p>
</>};
const _feasting_bite = {title: "Feasting Bite", jsx: <><p>This rage power is available to <Link to="/race/half_orc">half-orc</Link> barbarians. When the barbarian confirms a critical hit with her bite attack, she regains a number of hit points equal to half the damage dealt. The barbarian must have the <Link to="/ragepower/bloody_bite">bloody bite</Link> rage power and either the <Link to="/ragepower/animal_fury">animal fury</Link> rage power or a natural bite attack before selecting this power. Activating this ability consumes 1 round of rage.</p>
</>};
const _penetrating_bite = {title: "Penetrating Bite", jsx: <><p>When using the animal fury rage power while raging, the barbarian's bite is able to pierce most resistances. At 4th level, her bite is treated as a magic weapon for the purpose of overcoming damage reduction. At 7th level, her bite is also treated as cold iron and silver for the purpose of overcoming damage reduction. At 10th level, her bite is also treated as a chaotic weapon for the purpose of overcoming damage reduction. At 16th level, her bite is treated as an <Link to="/eq-material/adamantine">adamantine</Link> weapon for the purpose of overcoming damage reduction and bypassing hardness. A barbarian must have the <Link to="/ragepower/animal_fury">animal fury</Link> rage power and be at least 4th level to select this rage power.</p>
</>};
const _savage_jaw = {title: "Savage Jaw", jsx: <><p>While raging, the barbarian can open her jaw wide and latch her teeth firmly onto her opponent. While using the animal fury power, the barbarian can activate this power as a free action and gain the <Link to="/umr/grab">grab</Link> ability with her bite attack until the start of her next turn. This power can be used only once per rage. A barbarian must have the <Link to="/ragepower/animal_fury">animal fury</Link> rage power to select this rage power.</p>
</>};
const _vipers_kiss = {title: "Viper's Kiss", jsx: <><p>The barbarian can drink 1 dose of an ingested poison as a move action (instead of a standard action) as long as she starts the turn with the poison in her hand. She can hold this dose within her mouth for a number of rounds equal to her Constitution modifier (minimum 1 round) without suffering harmful effects. If the barbarian still holds the poison in her mouth after this time, she consumes the poison. While the dose is held within her mouth, the barbarian's next successful bite attack applies the effect of the poison with an immediate onset; this consumes the dose. A barbarian must have a bite attack (at least when raging, such as that granted by <Link to="/ragepower/animal_fury">animal fury</Link>) to select this rage power.</p>
</>};
const _vipers_breath = {title: "Viper's Breath", jsx: <><p>While holding a dose of poison in her mouth, the barbarian can exhale a 15-foot cone of inhaled poison. Anyone caught in the spray must succeed at a saving throw against the poison with a DC equal to the poison's DC - 4 or suffer the poison's effects with an immediate onset. A barbarian must have <Link to="/ragepower/vipers_kiss">viper's kiss</Link> to select this rage power.</p>
</>};
const _enhance_venom = {title: "Enhance Venom", jsx: <><p>The barbarian adds her Constitution modifier to the DC of any poison she delivers using viper's kiss or viper's breath. A barbarian must have <Link to="/ragepower/vipers_breath">viper's breath</Link> and <Link to="/ragepower/vipers_kiss">viper's kiss</Link> to select this rage power.</p>
</>};
const _armor_ripper = {title: "Armor Ripper", jsx: <><p>While raging, you gain a +2 bonus on combat maneuver checks made to <Link to="/rule/sunder">sunder</Link> with any of your natural attacks.</p>
</>};
const _auspicious_mark = {title: "Auspicious Mark", jsx: <><p>The barbarian has been marked by the spirits, as indicated by an impressive tattoo, scar, or birthmark she possesses. Once per rage, as a swift action that costs 2 rounds of rage, the barbarian can call upon the spirits' favor. Using auspicious mark grants her a +1d6 bonus on one d20 roll she has just made. She can call on the auspicious mark after seeing the result of the d20 roll.</p>
</>};
const _autumn_rage = {title: "Autumn Rage", jsx: <><p>The barbarian becomes a servant of the harvest. While raging, she gains a +2 bonus on combat maneuver checks to <Link to="/rule/reposition">reposition</Link> or <Link to="/rule/trip">trip</Link>. She also gains this bonus on attack rolls to confirm critical hits. A barbarian can have only one season-themed rage power, choosing between <Link to="/ragepower/spring_rage">spring</Link>, <Link to="/ragepower/summer_rage">summer</Link>, autumn, or <Link to="/ragepower/winter_rage">winter</Link> rage.</p>
</>};
const _bloody_fist = {title: "Bloody Fist", jsx: <><p>While raging, the barbarian may attempt to punch through an opponent's flesh and rip out one of its vital organs. In order to do so, the barbarian must confirm a critical hit against an opponent with a natural attack or unarmed strike. The barbarian deals damage as normal for a critical hit and the opponent must succeed at a Fortitude save (DC = 10 + 1/2 the barbarian's class level + the barbarian's Strength modifier) or take 1d4 points of <Link to="/rule/constitution_damage">Constitution damage</Link> as one of its vital organs is ripped free from its body. This power can only be used once per rage. A barbarian must be at least 12th level to select this rage power.</p>
</>};
const _feast_of_blood = {title: "Feast of Blood", jsx: <><p>While raging, the barbarian may feast on the organs of her foes and absorb their power. After successfully ripping out a creature's vital organ, the barbarian may eat the organ within 1 minute of extracting it as a full-round action that provokes attacks of opportunity. Once the organ is consumed, the barbarian recovers a number of hit points equal to the Hit Dice of the organ's owner. In addition, the barbarian gains any energy immunities or resistances the victim had, though the effectiveness of these resistances is halved (for instance, a barbarian who eats the heart of a creature with resist cold 10 would gain resist cold 5; energy immunities are reduced to resist energy 20). This energy resistance lasts for a number of rounds equal to half the Hit Dice of the creature whose organ was consumed. A barbarian must have the <Link to="/ragepower/bloody_fist">bloody fist</Link> rage power to select this rage power. A barbarian must be at least 14th level to select this rage power.</p>
</>};
const _boars_charge = {title: "Boar's Charge", jsx: <><p>While raging, when you hit with a gore attack as part of a charge, you automatically score a critical threat. You must still confirm the critical hit as normal. You must be at least 12th level to select this rage power.</p>
</>};
const _boasting_taunt = {title: "Boasting Taunt", jsx: <><p>While raging, the barbarian can incite a creature to attack her by making an Intimidate check to demoralize. If the check succeeds, the target is also <Link to="/misc/shaken">shaken</Link> as long as the barbarian is visible and raging or until it makes a melee attack against the barbarian. The barbarian receives a +2 circumstance bonus on this check for every alcoholic drink she has consumed during this rage. This is a language-dependent mind-affecting effect, and it relies on audible components. The barbarian must be at least 6th level to select this power.</p>
</>};
const _body_bludgeon = {title: "Body Bludgeon", jsx: <><p>While raging, if the barbarian pins an opponent that is smaller than her, she can then use that opponent as a two-handed <Link to="/misc/improvised_weapon">improvised weapon</Link> that deals 1d8 points of bludgeoning damage, assuming the opponent is sized Small. Larger or smaller creatures used as a bludgeon deal damage based on their size using this base damage. A size Tiny creature deals 1d6 points of damage, a size Medium creature deals 1d10 points of damage, and so on. The barbarian can make a single attack using the pinned opponent as part of the action she uses to maintain the grapple, using her highest attack bonus. Whenever the barbarian hits using the pinned opponent as a weapon, she deals damage to her target normally, and the grappled opponent used as a bludgeon also takes the same damage she dealt to the target. If the pinned opponent is unable to resist being pinned for any reason, the barbarian can use that opponent as an improvised weapon without grappling or pinning the opponent, until the creature is reduced to 0 or fewer hit points, at which point the creature becomes useless as an improvised weapon. A barbarian must be at least 10th level before selecting this rage power.</p>
</>};
const _brawler = {title: "Brawler", jsx: <><p>While raging, the barbarian is treated as if she has <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>. If she already has the feat, her unarmed strikes deal 1d6 points of damage (1d4 if she is Small).</p>
</>};
const _greater_brawler = {title: "Greater Brawler", jsx: <><p>While raging, the barbarian is treated as if she has <Link to="/feat/two_weapon_fighting">Two-Weapon Fighting</Link> when making unarmed strike attacks. A barbarian must have the <Link to="/ragepower/brawler">brawler</Link> rage power to select this rage power.</p>
</>};
const _breathtaker = {title: "Breathtaker", jsx: <><p>The barbarian's blows take the air from her foes' lungs. While raging, whenever the barbarian makes a successful melee attack against an opponent that is holding its breath, in addition to any other effects caused by that attack, the opponent loses a number of rounds of breath equal to the barbarian's Strength modifier.</p>
</>};
const _clear_mind = {title: "Clear Mind", jsx: <><p>A barbarian may reroll a failed Will save. This power is used as an immediate action after the first save is attempted, but before the results are revealed by the GM. The barbarian must take the second result, even if it is worse. A barbarian must be at least 8th level before selecting this power. This power can only be used once per rage.</p>
</>};
const _come_and_get_me = {title: "Come and Get Me", jsx: <><p>While raging, as a free action the barbarian may leave herself open to attack while preparing devastating counterattacks. Enemies gain a +4 bonus on attack and damage rolls against the barbarian until the beginning of her next turn, but every attack against the barbarian provokes an attack of opportunity from her, which is resolved prior to resolving each enemy attack. A barbarian must be at least 12th level to select this rage power.</p>
</>};
const _contagious_rage = {title: "Contagious Rage", jsx: <><p>The barbarian howls during combat, agitating nearby fauna. Willing animals and magical beasts within 30 feet of the barbarian gain the benefits of the <Link to="/spell/rage">rage</Link> spell for as long as she maintains her rage. After the barbarian's rage ends, creatures affected by her rage are fatigued for the same number of rounds as the barbarian. A barbarian must be at least 6th level to choose this rage power.</p>
</>};
const _deathless_frenzy = {title: "Deathless Frenzy", jsx: <><p>While raging, you ignore the effects of being at 0 or fewer hit points until you have been at 0 or fewer hit points for 1 round, at which point the appropriate consequences for your current hit point total take effect. Even death can be postponed this way, potentially allowing you to survive if you receive sufficient healing before the round is up. You must be at least 12th level to select this rage power.</p>
</>};
const _disemboweling_tusks = {title: "Disemboweling Tusks", jsx: <><p>While raging, when you confirm a critical hit with your gore attack, you deal 1d4 points of <Link to="/rule/constitution_damage">Constitution damage</Link> in addition to the normal damage for the gore attack. You must be at least 10th level to select this rage power.</p>
</>};
const _dissipating_rage = {title: "Dissipating Rage", jsx: <><p>When the barbarian rages, her feverish frenzy and hot breath burn or blow fog, smoke and similar effects away from her. The barbarian and creatures adjacent to her do not gain <Link to="/rule/concealment">concealment</Link> from obfuscating effects like fog or precipitation. Magical effects that require more than a strong wind to dissipate are not affected by this rage power.</p>
</>};
const _eclipsing_rage = {title: "Eclipsing Rage", jsx: <><p>While the barbarian is raging, the <Link to="/rule/light_level">light level</Link> within 10 feet of her lowers by one step. She can't decrease the light level below normal darkness with this ability. Multiple barbarians with this rage power don't further reduce the light level. A barbarian must be at least 6th level to choose this rage power.</p>
</>};
const _greater_eclipsing_rage = {title: "Greater Eclipsing Rage", jsx: <><p>Whenever the barbarian rages, the <Link to="/rule/light_level">light level</Link> within 20 feet of her lowers by two steps instead of one. She still can't decrease the light level below normal darkness with this ability. A barbarian must be at least 10th level and have the <Link to="/ragepower/eclipsing_rage">eclipsing rage</Link> rage power to choose this rage power.</p>
</>};
const _lesser_elemental_rage = {title: "Lesser Elemental Rage", jsx: <><p>As a swift action, the barbarian can cause her melee attacks to deal an additional 1d6 points of energy damage (acid, cold, electricity, or fire) for 1 round. A barbarian must be at least 4th level to select this rage power. This power can only be used once per rage.</p>
</>};
const _elemental_rage = {title: "Elemental Rage", jsx: <><p>While raging, all of the barbarian's melee attacks deal an additional 1d6 points of energy damage (acid, cold, electricity, or fire). The type is chosen when the barbarian begins her rage. A barbarian must have the <Link to="/ragepower/lesser_elemental_rage">lesser elemental rage</Link> power to select this rage power. A barbarian must be at least 8th level to select this rage power. Note that the barbarian can still use her lesser elemental rage power while using this rage power, but she must select a different energy type.</p>
</>};
const _greater_elemental_rage = {title: "Greater Elemental Rage", jsx: <><p>While raging, all of the barbarian's critical hits made with melee weapons deal an additional 1d10 points of energy damage (2d10 if the weapon deals &times;3 damage on a critical hit, 3d10 if the weapon deals &times;4 on a critical hit). The type of this damage is the same as the type chosen for the elemental rage power. A barbarian must have the <Link to="/ragepower/elemental_rage">elemental rage</Link> power to select this rage power. A barbarian must be at least 12th level to select this rage power.</p>
</>};
const _energy_resistance = {title: "Energy Resistance", jsx: <><p>While raging, the barbarian gains resistance to one energy type (acid, cold, electricity, fire, or sonic) equal to 1/2 her barbarian level (minimum 1). The energy type is chosen when this rage power is selected and it cannot be changed. This rage power can be selected more than once. Its effects do not stack. Each time is applies to a different energy type.</p>
</>};
const _greater_energy_resistance = {title: "Greater Energy Resistance", jsx: <><p>Once per rage, a barbarian can reduce damage by half from a single attack against which she has energy resistance (halve the damage, then apply resistance). A barbarian must have the <Link to="/ragepower/energy_resistance">energy resistance</Link> rage power to select this rage power. A barbarian must be at least 8th level to select this rage power.</p>
</>};
const _energy_absorption = {title: "Energy Absorption", jsx: <><p>While raging, the barbarian can absorb energy from a single attack of her chosen energy type once per rage. She does not make a saving throw against the effect but takes no damage from it, instead gaining 1 temporary hit point per 3 points of damage the attack would have inflicted. These <Link to="/rule/temporary_hit_points">temporary hit points</Link> last until the end of the barbarian's rage. A barbarian must have the <Link to="/ragepower/greater_energy_resistance">greater energy resistance</Link> rage power to select this rage power. A barbarian must be at least 12th level to select this rage power.</p>
</>};
const _energy_eruption = {title: "Energy Eruption", jsx: <><p>While raging, the barbarian can absorb energy from a single attack and unleash it upon her enemies once per rage. She does not make a saving throw against the effect but takes no damage from it. At any point during the remainder of her rage she can unleash the stored energy as a breath weapon in either a 60-foot line or 30-foot cone. The breath weapon inflicts damage equal to the damage from the attack absorbed by the barbarian, but creatures within the area may make a Reflex save (DC 10 + 1/2 the barbarian's level + the barbarian's Constitution modifier) for half damage even if the original effect did not allow a save. A barbarian must have the <Link to="/ragepower/energy_absorption">energy absorption</Link> rage power to select this rage power. A barbarian must be at least 16th level to select this rage power.</p>
</>};
const _erratic_charge = {title: "Erratic Charge", jsx: <><p>As part of the full-round action to perform a charge attack against a creature at least 20 feet away, the barbarian can move 5 feet in any direction before making the charge. This movement is not a 5-foot step and provokes attacks of opportunity as normal, and using this option reduces the maximum distance of the charge by 10 feet.</p>
</>};
const _greater_erratic_charge = {title: "Greater Erratic Charge", jsx: <><p>The barbarian can move 10 feet when using erratic charge. If she does so, the creature she is charging must be at least 20 feet away and the movement reduces the maximum distance of her charge by 20 feet. A barbarian must be at least 8th level and must have the <Link to="/ragepower/erratic_charge">erratic charge</Link> rage power before selecting this power.</p>
</>};
const _fearless_rage = {title: "Fearless Rage", jsx: <><p>While raging, the barbarian is immune to the shaken and frightened conditions. A barbarian must be at least 12th level before selecting this rage power.</p>
</>};
const _ferocious_beast = {title: "Ferocious Beast", jsx: <><p>While the barbarian is raging, her animal companion also gains the benefits of rage (including greater rage, mighty rage, and tireless rage), though the barbarian must spend 1 additional round of rage per round if her companion begins or ends its turn adjacent to her, and 2 additional rounds of rage per round if not.</p>
</>};
const _greater_ferocious_beast = {title: "Greater Ferocious Beast", jsx: <><p>While the barbarian is raging, her animal companion shares the benefits of the barbarian's rage powers that are constant in effect. It gains no benefit from rage powers that require actions to activate, even if they are free actions. A barbarian must have the <Link to="/ragepower/ferocious_beast">ferocious beast</Link> rage power and be at least 8th level to select this rage power.</p>
</>};
const _ferocious_mount = {title: "Ferocious Mount", jsx: <><p>While raging and mounted, the barbarian's mount also gains the benefits of rage (including greater rage and mighty rage) as long as the barbarian is mounted or adjacent to it. While her mount is raging in this way, she must spend one additional round of rage per round. She can elect not to pay this cost, in which case her mount does not rage.</p>
</>};
const _greater_ferocious_mount = {title: "Greater Ferocious Mount", jsx: <><p>While raging and mounted, the barbarian's mount gains the benefits of any rage powers that are constant in effect when the barbarian is raging. It does not gain the benefit of any rage powers that require actions to activate, even if they are free actions. A barbarian must have the <Link to="/ragepower/ferocious_mount">ferocious mount</Link> rage power to select this rage power. A barbarian must be at least 8th level to select this rage power.</p>
</>};
const _ferocious_trample = {title: "Ferocious Trample", jsx: <><p>While raging and mounted, the barbarian's mount gains the <Link to="/umr/trample">trample</Link> special attack. This attack inflicts 1d8 points of damage for a Medium mount, 2d6 for a Large mount, or 2d8 for a Huge mount, plus 1-1/2 times the mount's Strength modifier. A successful Reflex save (DC 10 + 1/2 the barbarian's level + the mount's Strength modifier) halves this damage. Creatures in the mount's path or that threaten squares it passes through may make attacks of opportunity against either the barbarian or the mount, but not both. A barbarian must have the <Link to="/ragepower/ferocious_mount">ferocious mount</Link> rage power to select this rage power. A barbarian must be at least 8th level to select this rage power.</p>
</>};
const _greater_ferocious_trample = {title: "Greater Ferocious Trample", jsx: <><p>A barbarian's mount can affect creatures up to its own size with its ferocious trample. In addition, it can make an <Link to="/rule/overrun">overrun</Link> combat maneuver check as a free action against a creature that fails its Reflex save (or chooses not to save in order to take an attack of opportunity) against its trample. A barbarian must have the <Link to="/ragepower/ferocious_trample">ferocious trample</Link> rage power to select this rage power. A barbarian must be at least 12th level to select this rage power.</p>
</>};
const _spirit_steed = {title: "Spirit Steed", jsx: <><p>While raging and mounted, the barbarian's mount gains DR/magic equal to 1/2 the barbarian's level. The mount's natural weapons count as magical for the purpose of overcoming damage reduction. A barbarian must have the <Link to="/ragepower/ferocious_mount">ferocious mount</Link> rage power to select this rage power. A barbarian must be at least 6th level to select this rage power.</p>
</>};
const _fierce_fortitude = {title: "Fierce Fortitude", jsx: <><p>The character gains a +4 bonus on saving throws against diseases and poison. A skald must be trained in Intimidate to select this rage power.</p>
</>};
const _flesh_wound = {title: "Flesh Wound", jsx: <><p>Once per rage, the barbarian can try to avoid serious harm from an attack. The barbarian must make a Fortitude save with a DC equal to the damage that would be dealt by the attack. The barbarian's armor check penalty applies on this saving throw. If the save succeeds, the barbarian takes half damage from the attack and the damage is nonlethal. The barbarian must elect to use this ability after the attack roll is made, but before the damage is rolled. A barbarian must be at least 10th level to select this rage power.</p>
</>};
const _flight_response = {title: "Flight Response", jsx: <><p>When a barbarian with this rage power attempts a saving throw against a fear effect, she can enter a rage as an immediate action (as long as she would normally be able to enter rage). This consumes 3 rounds of the barbarian's daily allotment of rage rounds, but the barbarian can maintain the rage each round on her turn normally. Any benefits from the barbarian's rage apply immediately, so she gains her bonus on Will saves against the effect that required the initial saving throw. Unlike most rage powers, this rage power's effects are useful only when the barbarian is not raging, so a skald can't grant this rage power to allies with raging song.</p>
</>};
const _fueled_by_vengeance = {title: "Fueled by Vengeance", jsx: <><p>While raging, whenever you deal weapon damage to a creature that dealt damage to you since the end of your last turn, add 1 round to your remaining number of rounds of rage for the current day. You can gain no more than 1 extra round of rage each round. You must be at least 6th level to select this rage power.</p>
</>};
const _furious_draw = {title: "Furious Draw", jsx: <><p>The barbarian is treated as having the <Link to="/feat/quick_draw">Quick Draw</Link> feat.</p>
</>};
const _furious_barrage = {title: "Furious Barrage", jsx: <><p>The barbarian is treated as having the <Link to="/feat/rapid_shot">Rapid Shot</Link> feat, but only for the purpose of attacking with thrown weapons. She need not meet the feat's prerequisites. A barbarian must be at least 4th level and must have the <Link to="/ragepower/furious_draw">furious draw</Link> rage power before selecting this power.</p>
</>};
const _ghost_rager = {title: "Ghost Rager", jsx: <><p>While raging, the barbarian deals normal damage to incorporeal creatures even when using nonmagical weapons. She also gains a +3 morale bonus to touch AC, which increases by 1 at 8th level and every 4 levels thereafter (to a maximum of +7 at 20th level). This can't raise her touch AC above her full AC. A barbarian must be at least 6th level before selecting this rage power.</p>
</>};
const _good_for_what_ails_you = {title: "Good for What Ails You", jsx: <><p>While raging, the barbarian who takes a drink of alcohol may attempt a new saving throw against one of the following conditions that may be affecting her: blinded, confused, dazzled, deafened, exhausted, fatigued, frightened, nauseated, panicked, shaken, or sickened. If she succeeds at the save, the effect is suppressed for the duration of the rage. She also may attempt a new saving throw if poisoned; a successful save counts against those required for a cure, but a failed save has no ill effect.</p>
</>};
const _ground_breaker = {title: "Ground Breaker", jsx: <><p>Once per rage, the barbarian can attack the floor around her as a standard action. This attack automatically hits and deals damage normally. If the barbarian manages to deal more damage than the floor's hardness, the space she occupies and all of the squares adjacent to her become <Link to="/rule/difficult_terrain">difficult terrain</Link>. Creatures in these squares, except the barbarian, must make a DC 15 Reflex save or be knocked <Link to="/rule/prone">prone</Link>. A barbarian must be at least 6th level to select this rage power.</p>
</>};
const _greater_ground_breaker = {title: "Greater Ground Breaker", jsx: <><p>When using the ground breaker rage power, the barbarian can extend the radius of the effect by 5 feet. This rage power can be selected up to three times, and its effects stack. A barbarian must have the <Link to="/ragepower/ground_breaker">ground breaker</Link> rage power and be at least 8th level before selecting this rage power.</p>
</>};
const _guarded_life = {title: "Guarded Life", jsx: <><p>While raging, if the barbarian is reduced below 0 hit points, 1 hit point of lethal damage per barbarian level is converted to nonlethal damage. If the barbarian is at negative hit points due to lethal damage, she immediately <Link to="/misc/stabilize">stabilizes</Link>.</p>
</>};
const _greater_guarded_life = {title: "Greater Guarded Life", jsx: <><p>When using the guarded life rage power, 1 additional hit point of lethal damage per barbarian level is converted to nonlethal damage. A barbarian must have the <Link to="/ragepower/guarded_life">guarded life</Link> rage power and be at least 6th level before selecting this rage power.</p>
</>};
const _guarded_stance = {title: "Guarded Stance", jsx: <><p>The barbarian gains a +1 dodge bonus to her Armor Class against melee attacks for a number of rounds equal to the barbarian's current Constitution modifier (minimum 1). This bonus increases by +1 for every 6 levels the barbarian has attained. Activating this ability is a move action that does not provoke an attack of opportunity.</p>
</>};
const _hissing_rage = {title: "Hissing Rage", jsx: <><p>Once per hour, the barbarian can spit venom at an adjacent enemy as a standard action. She must make a touch attack to successfully spit on a foe in this way, but she can also apply this poison as a swift action when she hits with a bite attack.</p>
<div className="sideNoteWrap"><ScrollContainer id="ragepower-hissing_rage--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={9} to="/rule/poison"><IonIcon aria-label="Poison" icon="/icons/poison-bottle.svg" /></ThLink><th colSpan={4} scope="col" className="title">Hissing Rage Poison</th></tr><tr><th scope="row">Type</th><td colSpan={3}>Bite-contact or injury</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Fort 10 + 1/2 the barbarian's level + her Con modifier</td></tr><tr><th scope="row">Onset</th><td colSpan={3}>immediate</td></tr><tr><th scope="row">Frequency</th><td colSpan={3}>1/round for 6 rounds</td></tr><tr><th scope="row">Effect</th><td colSpan={3}>1d2 <Link to="/rule/str_damage">Str damage</Link></td></tr><tr><th scope="row">Cure</th><td colSpan={3}>2 consecutive saves</td></tr></tbody></table></ScrollContainer></div></>};
const _lesser_hurling = {title: "Lesser Hurling", jsx: <><p>As a full-round action while raging, the barbarian can lift and hurl an object up to one size category smaller than herself with both hands or two size categories smaller with one hand as an improvised weapon with a range increment of 10 feet. This inflicts damage as a <Link to="/rule/falling_objects">falling object</Link> plus the barbarian's Strength bonus. This damage is halved if the object is not made of stone, metal, or similar material. This is a ranged touch attack, and the target may attempt a Reflex save (DC 10 + 1/2 the barbarian's level + the barbarian's Strength modifier) for half damage. The barbarian may apply <Link to="/feat/power_attack">Power Attack</Link> to this attack as a one- or two-handed weapon, as appropriate.</p>
</>};
const _hurling = {title: "Hurling", jsx: <><p>As lesser hurling, but the barbarian can increase the range increment to 20 feet or increase the size of a hurled object by one size category. A barbarian must have the <Link to="/ragepower/lesser_hurling">lesser hurling</Link> rage power to select this rage power. A barbarian must be at least 8th level to select this rage power.</p>
</>};
const _greater_hurling = {title: "Greater Hurling", jsx: <><p>As hurling, but the barbarian can increase the range increment to 30 feet or increase the size of a hurled object by two size categories. A barbarian must have the <Link to="/ragepower/hurling">hurling</Link> rage power to select this rage power. A barbarian must be at least 12th level to select this rage power.</p>
</>};
const _hurling_charge = {title: "Hurling Charge", jsx: <><p>While raging and making a charge attack, the barbarian may draw and throw a hurled weapon during her charge, gaining the normal +2 attack roll bonus on the thrown weapon attack as well as on the melee attack at the end of the charge. The barbarian must move at least 10 feet before using a thrown weapon and at least 10 additional feet before making a melee attack at the end of her charge. The barbarian must have a thrown weapon in hand or have one hand free at the beginning of her charge. A barbarian must have the <Link to="/ragepower/lesser_hurling">lesser hurling</Link> rage power to select this rage power. A barbarian must be at least 6th level to select this rage power.</p>
</>};
const _impelling_disarm = {title: "Impelling Disarm", jsx: <><p>Once per rage, the barbarian can make a <Link to="/rule/disarm">disarm</Link> attempt against a target in place of a melee attack. This attempt does not provoke attacks of opportunity. If successful, the barbarian sends the target's weapon flying - either straight at the target, or spinning away to strike another foe up to 20 feet away. This ranged attack has a -4 penalty, as it is treated as <Link to="/rule/weapons">throwing a weapon that isn't designed to be thrown</Link>, even if the weapon disarmed is a thrown weapon. The barbarian makes a ranged attack, which doesn't provoke attacks of opportunity, at either the target of his disarm maneuver or another creature within 20 feet. If the barbarian is aiming for the disarmed creature, the foe doesn't count as being in melee for determining any penalty on the ranged attack from throwing a ranged weapon into melee. If the ranged attack hits, the disarmed weapon deals damage as if the barbarian had thrown it. The barbarian can choose to aim the disarmed weapon at a square rather than at a foe. A barbarian must be at least 4th level to select this rage power.</p>
</>};
const _increased_damage_reduction = {title: "Increased Damage Reduction", jsx: <><p>The barbarian's damage reduction increases by 1/-. This increase is always active while the barbarian is raging. A barbarian can select this rage power up to three times. Its effects stack. A barbarian must be at least 8th level before selecting this rage power.</p>
</>};
const _internal_fortitude = {title: "Internal Fortitude", jsx: <><p>While raging, the barbarian is immune to the sickened and nauseated conditions. A barbarian must be at least 8th level before selecting this rage power.</p>
</>};
const _intimidating_glare = {title: "Intimidating Glare", jsx: <><p>The barbarian can make an Intimidate check against one adjacent foe as a move action. If the barbarian successfully demoralizes her opponent, the foe is shaken for 1d4 rounds + 1 round for every 5 points by which the barbarian's check exceeds the DC.</p>
</>};
const _battle_roar = {title: "Battle Roar", jsx: <><p>When the character successfully demoralizes an opponent using intimidating glare, he also deals 1d6 points of sonic damage to that opponent. A character must be at least 6th level and have the <Link to="/ragepower/intimidating_glare">intimidating glare</Link> rage power to select this rage power.</p>
</>};
const _terrifying_howl = {title: "Terrifying Howl", jsx: <><p>The barbarian unleashes a terrifying howl as a standard action. All shaken enemies within 30 feet must make a Will save (DC equal to 10 + 1/2 the barbarian's level + the barbarian's Strength modifier) or be panicked for 1d4+1 rounds. Once an enemy has made a save versus terrifying howl (successful or not), it is immune to this power for 24 hours. A barbarian must have the <Link to="/ragepower/intimidating_glare">intimidating glare</Link> rage power to select this rage power. A barbarian must be at least 8th level before selecting this power.</p>
</>};
const _inured_to_the_dead = {title: "Inured to the Dead", jsx: <><p>Once per rage, when the barbarian fails a saving throw against an effect created by an undead creature, she can reroll the saving throw. She must use the second result, even if it is worse. This does not require spending an action. A barbarian must be at least 4th level to select this rage power.</p>
</>};
const _knockback = {title: "Knockback", jsx: <><p>Once per round, the barbarian can make a <Link to="/rule/bull_rush">bull rush</Link> attempt against one target in place of a melee attack. If successful, the target takes damage equal to the barbarian's Strength modifier and is moved back as normal. The barbarian does not need to move with the target if successful. This does not provoke an attack of opportunity.</p>
</>};
const _knockdown = {title: "Knockdown", jsx: <><p>Once per rage, the barbarian can make a trip attack against one target in place of a melee attack. If successful, the target takes damage equal to the barbarian's Strength modifier and is knocked <Link to="/rule/prone">prone</Link>. This does not provoke an attack of opportunity.</p>
</>};
const _linnorm_death_curse = {title: "Linnorm Death Curse", notBookmarkable: true, jsx: <><h2 id="ragepower-linnorm_death_curse-linnorm-death-curse">Linnorm Death Curse</h2>
<p>"Linnorm Death Curse" can refer to seven different rage powers.</p>
<ol>
<li><Link to="/ragepower/cairn_linnorm_death_curse">Cairn Linnorm Death Curse</Link></li>
<li><Link to="/ragepower/crag_linnorm_death_curse">Crag Linnorm Death Curse</Link></li>
<li><Link to="/ragepower/fjord_linnorm_death_curse">Fjord Linnorm Death Curse</Link></li>
<li><Link to="/ragepower/ice_linnorm_death_curse">Ice Linnorm Death Curse</Link></li>
<li><Link to="/ragepower/taiga_linnorm_death_curse">Taiga Linnorm Death Curse</Link></li>
<li><Link to="/ragepower/tarn_linnorm_death_curse">Tarn Linnorm Death Curse</Link></li>
<li><Link to="/ragepower/tor_linnorm_death_curse">Tor Linnorm Death Curse</Link></li>
</ol>
</>};
const _cairn_linnorm_death_curse = {title: "Cairn Linnorm Death Curse", jsx: <><p>The character channels the power of a <Link to="/monster/cairn_linnorm">cairn linnorm</Link>. The character's melee attacks deal an additional 1 point of negative energy damage. If the character is knocked unconscious or killed by an attack or spell, the attacker suffers the <em>curse of decay</em> (Will negates). A character must be at least 8th level to select this rage power.</p>
<div className="sideNoteWrap"><ScrollContainer id="ragepower-cairn_linnorm_death_curse--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/curses"><IonIcon aria-label="Curse" icon="/icons/death-note.svg" /></ThLink><th colSpan={4} scope="col" className="title">Curse of Decay</th></tr><tr><th scope="row">Type</th><td colSpan={3}>Curse</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Will 10 + 1/2 the character's level + their Charisma modifier</td></tr><tr><th scope="row">Effect</th><td colSpan={3}>Target takes 1 point of <Link to="/rule/con_damage">Con damage</Link> per day and <Link to="/rule/age">ages</Link> at a rate of 1 year per day (eventually incurring all of the penalties of old age but none of the bonuses)</td></tr></tbody></table></ScrollContainer></div></>};
const _crag_linnorm_death_curse = {title: "Crag Linnorm Death Curse", jsx: <><p>The character channels the power of a <Link to="/monster/crag_linnorm">crag linnorm</Link>. The character's melee attacks deal an additional 1 point of fire damage. If the character is knocked unconscious or killed by an attack or spell, the attacker suffers the <em>curse of fire</em> (Will negates). A character must be at least 4th level to select this rage power.</p>
<div className="sideNoteWrap"><ScrollContainer id="ragepower-crag_linnorm_death_curse--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/curses"><IonIcon aria-label="Curse" icon="/icons/death-note.svg" /></ThLink><th colSpan={4} scope="col" className="title">Curse of Fire</th></tr><tr><th scope="row">Type</th><td colSpan={3}>Curse</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Will 10 + 1/2 the character's level + their Charisma modifier</td></tr><tr><th scope="row">Effect</th><td colSpan={3}>Target gains <Link to="/umr/vulnerability">vulnerability</Link> to fire</td></tr></tbody></table></ScrollContainer></div></>};
const _fjord_linnorm_death_curse = {title: "Fjord Linnorm Death Curse", jsx: <><p>The character channels the power of a <Link to="/monster/fjord_linnorm">fjord linnorm</Link>. The character's melee attacks deal an additional 1 point of cold damage. If the character is knocked unconscious or killed by an attack or spell, the attacker suffers the <em>curse of drowning</em> (Will negates). A character must be at least 4th level to select this rage power.</p>
<div className="sideNoteWrap"><ScrollContainer id="ragepower-fjord_linnorm_death_curse--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/curses"><IonIcon aria-label="Curse" icon="/icons/death-note.svg" /></ThLink><th colSpan={4} scope="col" className="title">Curse of Drowning</th></tr><tr><th scope="row">Type</th><td colSpan={3}>Curse</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Will 10 + 1/2 the character's level + their Charisma modifier</td></tr><tr><th scope="row">Effect</th><td colSpan={3}>Target is unable to breathe water (even with magic), can hold its breath only half as long as normal, and is <Link to="/misc/sickened">sickened</Link> whenever it holds its breath</td></tr></tbody></table></ScrollContainer></div></>};
const _ice_linnorm_death_curse = {title: "Ice Linnorm Death Curse", jsx: <><p>The character channels the power of an <Link to="/monster/ice_linnorm">ice linnorm</Link>. The character's melee attacks deal an additional 1 point of cold damage. If the character is knocked unconscious or killed, the attacker suffers the <em>curse of frost.</em> A character must be at least 4th level to select this rage power.</p>
<div className="sideNoteWrap"><ScrollContainer id="ragepower-ice_linnorm_death_curse--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/curses"><IonIcon aria-label="Curse" icon="/icons/death-note.svg" /></ThLink><th colSpan={4} scope="col" className="title">Curse of Frost</th></tr><tr><th scope="row">Type</th><td colSpan={3}>Curse</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Will 10 + 1/2 the character's level + their Charisma modifier</td></tr><tr><th scope="row">Effect</th><td colSpan={3}>Target gains <Link to="/umr/vulnerability">vulnerability</Link> to cold</td></tr></tbody></table></ScrollContainer></div></>};
const _taiga_linnorm_death_curse = {title: "Taiga Linnorm Death Curse", jsx: <><p>The character channels the power of a <Link to="/monster/taiga_linnorm">taiga linnorm</Link>. The character's melee attacks deal an additional 1 point of electricity damage. If the character is knocked unconscious or killed by an attack or spell, the attacker suffers the <em>curse of electricity</em> (Will negates). A character must be at least 4th level to select this rage power.</p>
<div className="sideNoteWrap"><ScrollContainer id="ragepower-taiga_linnorm_death_curse--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/curses"><IonIcon aria-label="Curse" icon="/icons/death-note.svg" /></ThLink><th colSpan={4} scope="col" className="title">Curse of Electricity</th></tr><tr><th scope="row">Type</th><td colSpan={3}>Curse</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Will 10 + 1/2 the character's level + their Charisma modifier</td></tr><tr><th scope="row">Effect</th><td colSpan={3}>Target gains <Link to="/umr/vulnerability">vulnerability</Link> to electricity</td></tr></tbody></table></ScrollContainer></div></>};
const _tarn_linnorm_death_curse = {title: "Tarn Linnorm Death Curse", jsx: <><p>The character channels the power of a <Link to="/monster/tarn_linnorm">tarn linnorm</Link>. The character's melee attacks deal an additional 1 point of acid damage. If the character is knocked unconscious or killed by an attack or spell, the attacker suffers the <em>curse of death</em> (Will negates). A character must be at least 4th level to select this rage power.</p>
<div className="sideNoteWrap"><ScrollContainer id="ragepower-tarn_linnorm_death_curse--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/curses"><IonIcon aria-label="Curse" icon="/icons/death-note.svg" /></ThLink><th colSpan={4} scope="col" className="title">Curse of Death</th></tr><tr><th scope="row">Type</th><td colSpan={3}>Curse</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Will 10 + 1/2 the character's level + their Charisma modifier</td></tr><tr><th scope="row">Effect</th><td colSpan={3}>Target is no longer affected by healing spells and can't heal damage naturally by resting</td></tr></tbody></table></ScrollContainer></div></>};
const _tor_linnorm_death_curse = {title: "Tor Linnorm Death Curse", jsx: <><p>The character channels the power of a <Link to="/monster/tor_linnorm">tor linnorm</Link>. The character's melee attacks deal an additional 1 point of fire damage. If the character is knocked unconscious or killed by an attack or spell, the attacker suffers the <em>curse of boiling blood</em> (Will negates). A character must be at least 8th level to select this rage power.</p>
<div className="sideNoteWrap"><ScrollContainer id="ragepower-tor_linnorm_death_curse--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/curses"><IonIcon aria-label="Curse" icon="/icons/death-note.svg" /></ThLink><th colSpan={4} scope="col" className="title">Curse of Boiling Blood</th></tr><tr><th scope="row">Type</th><td colSpan={3}>Curse</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Will 10 + 1/2 the character's level + their Charisma modifier</td></tr><tr><th scope="row">Effect</th><td colSpan={3}>Target gains <Link to="/umr/vulnerability">vulnerability</Link> to fire and is permanently <Link to="/misc/staggered">staggered</Link> from the pain of its boiling blood (this is a pain effect)</td></tr></tbody></table></ScrollContainer></div></>};
const _liquid_courage = {title: "Liquid Courage", jsx: <><p>While raging, the barbarian increases her morale bonus on saving throws against mind-affecting effects by +1 for each alcoholic drink she consumes during her rage, to a maximum of +1 increase per four barbarian levels.</p>
</>};
const _lizard_stride = {title: "Lizard Stride", jsx: <><p>When the barbarian makes a charge or run action while raging, she can move across the surface of water without sinking. She sinks immediately if she ends her turn standing on water.</p>
</>};
const _low_light_vision = {title: "Low-Light Vision", jsx: <><p>The barbarian's senses sharpen and she gains low-light vision while raging.</p>
</>};
const _night_vision = {title: "Night Vision", jsx: <><p>The barbarian's senses grow incredibly sharp while raging and she gains darkvision 60 feet. A barbarian must have <Link to="/ragepower/low_light_vision">low-light vision</Link> as a rage power or a racial trait to select this rage power.</p>
</>};
const _master_of_the_deep = {title: "Master of the Deep", jsx: <><p>As a standard action, the barbarian commands an aquatic creature to do her bidding. The barbarian selects a creature with the aquatic type within 30 feet and gives a terse command from those listed in the <Link to="/spell/command">command</Link> spell. Alternatively, if the creature has an Intelligence of 1 or 2, the barbarian may instead command the creature to attack the closest creature to it as a standard action. The creature must succeed at a Will save (DC equal to 10 + half the barbarian's level + her Strength modifier) or obey the command to the best of its ability on its next turn. Once a creature has attempted a saving throw against master of the deep (successful or not), it is immune to this power for 24 hours. This ability is a mind-affecting effect, but it is not language dependent; the creature need not understand the barbarian giving the command. A barbarian must be at least 8th level before selecting this power.</p>
</>};
const _mighty_swing = {title: "Mighty Swing", jsx: <><p>The barbarian automatically confirms a critical hit. This power is used as an immediate action once a critical threat has been determined. A barbarian must be at least 12th level before selecting this power. This power can only be used once per rage.</p>
</>};
const _moment_of_clarity = {title: "Moment of Clarity", jsx: <><p>The barbarian does not gain any benefits or take any of the penalties from rage for 1 round. Activating this power is a swift action. This includes the penalty to Armor Class and the restriction on what actions can be performed. This round still counts against her total number of rounds of rage per day. This power can only be used once per rage.</p>
</>};
const _perfect_clarity = {title: "Perfect Clarity", jsx: <><p>While using her moment of clarity rage power, the barbarian can roll twice for any miss chance or Will saving throws to disbelieve illusions, taking the better result. A barbarian must have the <Link to="/ragepower/moment_of_clarity">moment of clarity</Link> rage power before selecting this rage power.</p>
</>};
const _ultimate_clarity = {title: "Ultimate Clarity", jsx: <><p>Once per rage, the character can refine her senses, seeing through normal and magical darkness (including from magical effects such as <Link to="/spell/blur">blur</Link> and <Link to="/spell/displacement">displacement</Link>), <Link to="/spell/invisibility">invisibility</Link>, and illusions; she can also discern the exact locations of creatures with <Link to="/rule/concealment">concealment</Link>. This lasts for 1 round. A character must be at least 6th level and have the <Link to="/ragepower/moment_of_clarity">moment of clarity</Link> and <Link to="/ragepower/perfect_clarity">perfect clarity</Link> rage powers to select this rage power. The character does not need to be using moment of clarity to use this rage power.</p>
</>};
const _overbearing_advance = {title: "Overbearing Advance", jsx: <><p>While raging, the barbarian inflicts damage equal to her Strength bonus whenever she succeeds at an <Link to="/rule/overrun">overrun</Link> combat maneuver.</p>
</>};
const _overbearing_onslaught = {title: "Overbearing Onslaught", jsx: <><p>While raging, the barbarian may <Link to="/rule/overrun">overrun</Link> more than one target per round, with a -2 penalty on her CMB for each overrun check after the first. A barbarian must have the <Link to="/ragepower/overbearing_advance">overbearing advance</Link> rage power to select this rage power. A barbarian must be at least 6th level to select this rage power.</p>
</>};
const _no_escape = {title: "No Escape", jsx: <><p>The barbarian can move up to double her normal speed as an immediate action but she can only use this ability when an adjacent foe uses a <Link to="/rule/withdraw">withdraw</Link> action to move away from her. She must end her movement adjacent to the enemy that used the withdraw action. The barbarian provokes attacks of opportunity as normal during this movement. This power can only be used once per rage.</p>
</>};
const _pack_rage = {title: "Pack Rage", jsx: <><p>When a barbarian with this rage power enters a rage, any barbarian within 30 feet who also has this rage power can enter a rage. A barbarian that enters a rage outside of her turn spends 1 round of rage immediately and then spends another round of rage to maintain her rage at the beginning of her next turn. A barbarian must be at least 6th level to choose this rage power.</p>
</>};
const _powerful_blow = {title: "Powerful Blow", jsx: <><p>The barbarian gains a +1 bonus on a single damage roll. This bonus increases by +1 for every 4 levels the barbarian has attained. This power is used as a swift action before the roll to hit is made. This power can only be used once per rage.</p>
</>};
const _bleeding_blow = {title: "Bleeding Blow", jsx: <><p>When she uses her powerful blow rage power, the barbarian also deals <Link to="/rule/bleed">bleed</Link> damage equal to her bonus damage with the powerful blow. This bleed damage bypasses damage reduction. A barbarian must have the <Link to="/ragepower/powerful_blow">powerful blow</Link> rage power and be at least 8th level before selecting this rage power.</p>
</>};
const _crippling_blow = {title: "Crippling Blow", jsx: <><p>When using her powerful blow rage power, the barbarian can forgo the normal bonus to damage (including any bleed damage granted by the <Link to="/ragepower/bleeding_blow">bleeding blow</Link> rage power or similar boosts to the damage of the powerful blow rage power) and instead deals 1 point of ability damage to the target's Strength or Dexterity score for every four class levels the barbarian has attained. The target can attempt a Fortitude saving throw (DC 10 + 1/2 the barbarian's level + the barbarian's Strength modifier) to halve this ability damage. A barbarian must have the <Link to="/ragepower/powerful_blow">powerful blow</Link> rage power and be at least 8th level before selecting this rage power.</p>
</>};
const _quick_reflexes = {title: "Quick Reflexes", jsx: <><p>While raging, the barbarian can make one additional attack of opportunity per round.</p>
</>};
const _raging_climber = {title: "Raging Climber", jsx: <><p>When raging, the barbarian adds her level as an enhancement bonus on all Climb skill checks.</p>
</>};
const _bestial_climber = {title: "Bestial Climber", jsx: <><p>While raging, the barbarian gains a natural climb speed equal to her land speed. A barbarian must have the <Link to="/ragepower/raging_climber">raging climber</Link> rage power and be at least 6th level before selecting this rage power.</p>
</>};
const _raging_flyer = {title: "Raging Flyer", jsx: <><p>When raging, the barbarian adds her level as an enhancement bonus to Fly checks.</p>
</>};
const _bestial_flyer = {title: "Bestial Flyer", jsx: <><p>While raging, the barbarian's fly speed increases by 10 feet and her maneuverability improves by one category. A barbarian must have a fly speed before raging, have the <Link to="/ragepower/raging_flyer">raging flyer</Link> power, and be at least 6th level to choose this rage power.</p>
</>};
const _raging_leaper = {title: "Raging Leaper", jsx: <><p>When raging, the barbarian adds her level as an enhancement bonus on all <Link to="/skill/acrobatics">Acrobatics</Link> skill checks made to jump. When making a jump in this way, the barbarian is always considered to have a running start.</p>
</>};
const _bestial_leaper = {title: "Bestial Leaper", jsx: <><p>While raging, the barbarian can take a move action to move and can take her normal standard action at any point during the move. A barbarian must have the <Link to="/ragepower/raging_leaper">raging leaper</Link> rage power and be at least 6th level before selecting this rage power.</p>
</>};
const _raging_flier = {title: "Raging Flier", jsx: <><p>Once per rage, the character can fly up to her base speed as a move action. If she uses the charge action, she can use this flight as part of her movement during the charge. A character must be at least 6th level and have the <Link to="/ragepower/raging_leaper">raging leaper</Link> rage power to select this rage power.</p>
</>};
const _raging_grappler = {title: "Raging Grappler", jsx: <><p>While raging, the barbarian grapples her foes with the power and viciousness of a river crocodile. As long as she is raging, whenever the barbarian succeeds at a check to start a <Link to="/rule/grapple">grapple</Link>, she can choose to deal damage as if she had also succeeded at a check to maintain the grapple. In addition, while she is raging, whenever the barbarian succeeds at a combat maneuver check to maintain a grapple, she can choose to give herself, the target of her grapple, or both the <Link to="/rule/prone">prone</Link> condition as a free action while continuing to maintain the grapple.</p>
</>};
const _raging_swimmer = {title: "Raging Swimmer", jsx: <><p>When raging, the barbarian adds her level as an enhancement bonus on all Swim skill checks.</p>
</>};
const _bestial_swimmer = {title: "Bestial Swimmer", jsx: <><p>While raging, the barbarian gains a natural swim speed equal to her normal land speed. A barbarian must have the <Link to="/ragepower/raging_swimmer">raging swimmer</Link> rage power and be at least 6th level before selecting this rage power.</p>
</>};
const _raging_whirlwind = {title: "Raging Whirlwind", jsx: <><p>The barbarian can create a whirlwind with a powerful spinning move as an immediate action after she confirms a critical hit with a melee attack. The whirlwind circles the target of her melee attack, lifting it in the air slightly until the end of the barbarian's turn. The creature can attempt a Fortitude save (DC = 10 + half the barbarian's level + the barbarian's Constitution modifier) to negate this effect. If it fails the save, the target loses its Dexterity modifier to AC for the rest of the barbarian's turn and lands prone on the ground at the end of her turn. Raging whirlwind has no effect on flying creatures. A barbarian must be at least 12th level to choose this rage power.</p>
</>};
const _reckless_abandon = {title: "Reckless Abandon", jsx: <><p>While raging, the barbarian can take a -1 penalty to AC to gain a +1 bonus on attack rolls. The AC penalty increases by -1 and the attack roll bonus increases by +1 at 4th level and every four levels thereafter.</p>
</>};
const _inspire_ferocity = {title: "Inspire Ferocity", jsx: <><p>While raging, the barbarian can use a move action to impart her reckless abandon modifier to all willing allies within 30 feet for a number of rounds equal to her Charisma modifier (minimum 1). A barbarian must have the <Link to="/ragepower/reckless_abandon">reckless abandon</Link> rage power to select this rage power.</p>
</>};
const _renewed_vigor = {title: "Renewed Vigor", jsx: <><p>As a standard action, the barbarian heals 1d8 points of damage + her Constitution modifier. For every four levels the barbarian has attained above 4th, this amount of damage healed increases by 1d8, to a maximum of 5d8 at 20th level. A barbarian must be at least 4th level before selecting this power. This power can be used only once per day and only while raging.</p>
</>};
const _regenerative_vigor = {title: "Regenerative Vigor", jsx: <><p>After using her renewed vigor rage power until her current rage ends, the barbarian gains <Link to="/umr/fast_healing">fast healing</Link> 1 for every 6 barbarian levels she has (maximum fast healing 3). She regains hit points from fast healing at the start of each of her turns. A barbarian must have the <Link to="/ragepower/renewed_vigor">renewed vigor</Link> rage power and be at least 6th level before selecting this rage power.</p>
</>};
const _renewed_vitality = {title: "Renewed Vitality", jsx: <><p>While raging, the barbarian ignores the effect of 1 point of ability penalty or damage per two barbarian levels she has (maximum 10). Once per day, when a barbarian with ability penalties or damage ends her rage, she can reroll a saving throw, if any, against an effect that imposed an ability penalty or dealt her ability damage. If successful, she removes an amount of ability penalty or damage equal to the amount she can ignore while raging. A barbarian must have the <Link to="/ragepower/renewed_vigor">renewed vigor</Link> rage power and be at least 4th level before selecting this rage power.</p>
</>};
const _renewed_life = {title: "Renewed Life", jsx: <><p>While raging, the barbarian ignores the effect of one temporary negative level per four barbarian levels she has (maximum 5). Once per day, when a barbarian with temporary negative levels ends her rage, she can attempt saving throws to remove a number of negative levels equal to the number of levels she could ignore while raging. A barbarian must have the <Link to="/ragepower/renewed_vitality">renewed vitality</Link> rage power and be at least 6th level before selecting this rage power.</p>
</>};
const _roaring_drunk = {title: "Roaring Drunk", jsx: <><p>While raging, the barbarian gains a +1 morale bonus on Intimidate checks and to the save DC of any fear effects she creates for each alcoholic drink she has consumed during her rage, to a maximum of +1 per four barbarian levels.</p>
</>};
const _rolling_dodge = {title: "Rolling Dodge", jsx: <><p>The barbarian gains a +1 dodge bonus to her Armor Class against ranged attacks for a number of rounds equal to the barbarian's current Constitution modifier (minimum 1). This bonus increases by +1 for every 6 levels the barbarian has attained. Activating this ability is a move action that does not provoke an attack of opportunity.</p>
</>};
const _reflexive_dodge = {title: "Reflexive Dodge", jsx: <><p>While using her rolling dodge rage power, the barbarian may apply her dodge bonus to AC as a bonus on Reflex saving throws. A barbarian must have the <Link to="/ragepower/rolling_dodge">rolling dodge</Link> rage power and be at least 6th level before selecting this rage power.</p>
</>};
const _roused_anger = {title: "Roused Anger", jsx: <><p>The barbarian may enter a rage even if fatigued. While raging after using this ability, the barbarian is immune to the <Link to="/misc/fatigued">fatigued</Link> condition. Once this rage ends, the barbarian is <Link to="/misc/exhausted">exhausted</Link> for 10 minutes per round spent raging.</p>
</>};
const _savage_dirty_trick = {title: "Savage Dirty Trick", jsx: <><p>Once per round while raging, (6th) the barbarian can attempt a <Link to="/rule/dirty_trick">dirty trick</Link> combat maneuver in place of a melee attack. This attempt does not provoke attacks of opportunity. If successful, the target takes an amount of damage equal to the barbarian's Strength modifier and must succeed at a Fortitude save (DC 10 + 1/2 the barbarian's level + the barbarian's Strength modifier) or take an additional penalty from the dirty trick based on the type of dirty trick performed and the following table.</p>
<ScrollContainer id="ragepower-savage_dirty_trick--table-0"><table>
<thead>
<tr>
<th>Initial Penalty</th>
<th>Additional Penalty</th>
</tr>
</thead>
<tbody><tr>
<td className="ion-activatable"><Link to="/misc/blinded">Blinded<IonRippleEffect /></Link></td>
<td className="ion-activatable"><Link to="/misc/staggered">Staggered<IonRippleEffect /></Link></td>
</tr>
<tr>
<td className="ion-activatable"><Link to="/misc/dazzled">Dazzled<IonRippleEffect /></Link></td>
<td className="ion-activatable"><Link to="/misc/dazed">Dazed<IonRippleEffect /></Link></td>
</tr>
<tr>
<td className="ion-activatable"><Link to="/misc/deafened">Deafened<IonRippleEffect /></Link></td>
<td>Staggered</td>
</tr>
<tr>
<td className="ion-activatable"><Link to="/rule/entangled">Entangled<IonRippleEffect /></Link></td>
<td>Anchored in place and unable to move from that square</td>
</tr>
<tr>
<td className="ion-activatable"><Link to="/misc/sickened">Sickened<IonRippleEffect /></Link></td>
<td className="ion-activatable"><Link to="/misc/nauseated">Nauseated<IonRippleEffect /></Link></td>
</tr>
</tbody></table></ScrollContainer>
<p>On a failed Fortitude save, the opponent takes this additional penalty on top of the dirty trick's original effect. The additional penalty lasts for 1 round (though the initial penalty lasts as long as normal), and can be removed with a move action. The initial effect cannot be removed via mundane means until the additional penalty is removed (though magical effects like <Link to="/spell/remove_blindness_deafness">remove blindness/deafness</Link> work). Removing the initial effect also removes the additional penalty. If the target is immune to the initial penalty, then it is unaffected by the additional penalty.</p>
<p>For example, a barbarian using this rage power attempts a dirty trick combat maneuver against her opponent to blind him. She succeeds and her opponent fails his Fortitude save, so he becomes staggered as well as blinded. Regardless of whether he had succeeded at his saving throw, the opponent still takes an amount of damage from the barbarian's combat maneuver equal to the barbarian's Strength modifier (unless he has damage reduction or would otherwise be able to prevent this damage). Likewise, if her opponent were immune to blinding effects, he would not suffer from the blindness or the staggering effect, regardless of his saving throw.</p>
<p>This power can only be used once per opponent per rage. A barbarian must be at least 6th level to select this rage power.</p>
</>};
const _savage_hurl = {title: "Savage Hurl", jsx: <><p>The barbarian gains a +1 bonus on ranged attack rolls with thrown weapons that add her Dexterity bonus to the attack roll. This bonus increases to +2 at 4th level if the barbarian's Strength modifier is at least +4, to +3 at 8th level if her Strength modifier is at least +6, and to +4 at 12th level if her Strength modifier is at least +8.</p>
</>};
const _savage_intuition = {title: "Savage Intuition", jsx: <><p>Your bestial senses allow you to sense danger and become enraged before you even have time to consciously react to danger. When combat begins, if you have rounds of rage remaining, you may automatically enter a rage without using an action at the start of the first round of combat (or at the start of the surprise round, if there is one), even if you are not otherwise aware that combat has begun.</p>
</>};
const _scent = {title: "Scent", jsx: <><p>The barbarian gains the <Link to="/umr/scent">scent</Link> ability while raging and can use this ability to locate unseen foes.</p>
</>};
const _primal_scent = {title: "Primal Scent", jsx: <><p>When using her scent rage power, the barbarian adds half her barbarian level on Survival checks made to track by scent and on Perception checks to pinpoint the location of creatures she cannot see. If she pinpoints the location of a creature that has total concealment, she treats it as having <Link to="/rule/concealment">concealment</Link>. A barbarian must have the <Link to="/ragepower/scent">scent</Link> rage power and be at least 8th level before selecting this rage power.</p>
</>};
const _smasher = {title: "Smasher", jsx: <><p>Once per rage, whenever the barbarian makes an attack against an unattended object or a <Link to="/rule/sunder">sunder</Link> combat maneuver, she can ignore the object's hardness. This ability must be used before the attack roll or sunder check is made.</p>
</>};
const _gearbreaker = {title: "Gearbreaker", jsx: <><p>Once per round while raging, whenever the barbarian makes an attack against a construct, she can ignore an amount of that construct's hardness equal to her barbarian level. This ability must be used before the attack roll is made. A barbarian must have the <Link to="/ragepower/smasher">smasher</Link> rage power before selecting this rage power. This power stacks with the <em>hard hitter</em> ability from the <Link to="/arc-barbarian/numerian_liberator">Numerian liberator</Link> archetype.</p>
</>};
const _spiritual_awareness = {title: "Spiritual Awareness", jsx: <><p>While raging, the barbarian's dodge bonus to AC from trap sense applies against attacks made by incorporeal creatures. The barbarian must have <Link to="/ability/trap_sense">trap sense</Link> to select this ability.</p>
</>};
const _spring_rage = {title: "Spring Rage", jsx: <><p>The barbarian's rage rejuvenates her physically and spiritually. While raging, she ignores penalties to her ability scores due to <Link to="/rule/aging">aging</Link>. She also ignores penalties from negative levels, though she retains any negative levels she has until they are removed normally. A barbarian can have only one season-themed rage power, choosing between spring, <Link to="/ragepower/summer_rage">summer</Link>, <Link to="/ragepower/autumn_rage">autumn</Link>, or <Link to="/ragepower/winter_rage">winter</Link> rage.</p>
</>};
const _staggering_drunk = {title: "Staggering Drunk", jsx: <><p>While raging, a barbarian gains a +1 dodge bonus to AC against attacks of opportunity for each alcoholic drink she has consumed during her rage, to a maximum of +1 per four barbarian levels.</p>
</>};
const _strength_surge = {title: "Strength Surge", jsx: <><p>The barbarian adds her barbarian level on one Strength check or combat maneuver check, or to her Combat Maneuver Defense when an opponent attempts a maneuver against her. This power is used as an immediate action. This power can only be used once per rage.</p>
</>};
const _suffocating_grip = {title: "Suffocating Grip", jsx: <><p>While raging, when the barbarian successfully maintains a grapple, she can choke her opponent instead of dealing damage to, moving, pinning, or tying up her opponent. The grappled opponent cannot speak or breathe and must hold its breath or begin <Link to="/rule/suffocation">suffocating</Link>. The grappled opponent can take a breath during any round in which the barbarian does not maintain the grapple. Creatures that do not breathe are not affected by this ability.</p>
</>};
const _greater_suffocating_grip = {title: "Greater Suffocating Grip", jsx: <><p>When the barbarian is using the suffocating grip rage power, the grappled creature cannot hold its breath and immediately begins <Link to="/rule/suffocation">suffocating</Link>. A barbarian must be at least 12th level and have the <Link to="/ragepower/suffocating_grip">suffocating grip</Link> rage power to select this rage power.</p>
</>};
const _summer_rage = {title: "Summer Rage", jsx: <><p>The barbarian channels the heat of late summer, making the air around her hot and oppressive. A creature within the barbarian's reach becomes <Link to="/misc/fatigued">fatigued</Link> as long as it remains within the barbarian's reach unless it succeeds at a Fortitude save (DC = 10 + half the barbarian's level + her Constitution modifier) to become immune for 24 hours. A barbarian can have only one season-themed rage power, choosing between <Link to="/ragepower/spring_rage">spring</Link>, summer, <Link to="/ragepower/autumn_rage">autumn</Link>, or <Link to="/ragepower/winter_rage">winter</Link> rage.</p>
</>};
const _superstition = {title: "Superstition", jsx: <><p>The barbarian gains a +2 morale bonus on saving throws made to resist spells, supernatural abilities, and spell-like abilities. This bonus increases by +1 for every 4 levels the barbarian has attained. While raging, the barbarian cannot be a willing target of any spell and must make saving throws to resist all spells, even those cast by allies.</p>
</>};
const _disruptive = {title: "Disruptive", jsx: <><p>When raging, the barbarian gains <Link to="/feat/disruptive">Disruptive</Link> as a bonus feat. The barbarian must have the <Link to="/ragepower/superstition">superstition</Link> rage power to select this rage power. A barbarian must be at least 8th level to select this rage power.</p>
</>};
const _eater_of_magic = {title: "Eater of Magic", jsx: <><p>Once per rage, when a barbarian fails a saving throw against a spell, supernatural ability, or spell-like ability, she can reroll the saving throw against the effect (this is not an action). If she succeeds at the second saving throw, she is not affected by the spell, supernatural ability, or spell-like ability and gains a number of <Link to="/rule/temporary_hit_points">temporary hit points</Link> equal to the effect's caster level (in the case of spell or spell-like abilities) or the CR of the effect's creator (in the case of supernatural abilities). These temporary hit points last until damage is applied to them or 1 minute, whichever occurs first. A barbarian must have the <Link to="/ragepower/superstition">superstition</Link> rage power and be at least 10th level before selecting this rage power.</p>
</>};
const _spellbreaker = {title: "Spellbreaker", jsx: <><p>When raging, the barbarian gains <Link to="/feat/spellbreaker">Spellbreaker</Link> as a bonus feat. A barbarian must have the <Link to="/ragepower/disruptive">disruptive</Link> rage power and be at least 12th level to select this rage power.</p>
</>};
const _witch_hunter = {title: "Witch Hunter", jsx: <><p>While raging, the barbarian gains a +1 bonus on damage rolls against creatures possessing spells or spell-like abilities. This damage bonus increases by +1 for every four levels the barbarian has obtained. A barbarian must have the <Link to="/ragepower/superstition">superstition</Link> rage power to select this rage power.</p>
</>};
const _spell_sunder = {title: "Spell Sunder", jsx: <><p>Once per rage, the barbarian can attempt to <Link to="/rule/sunder">sunder</Link> an ongoing spell effect by succeeding at a combat maneuver check. For any effect other than one on a creature, the barbarian must make her combat maneuver check against a CMD of 15 plus the effect's caster level. To sunder an effect on a creature, the barbarian must succeed at a normal sunder combat maneuver against the creature's CMD + 5, ignoring any miss chance caused by a spell or spell-like ability. If successful, the barbarian suppresses the effect for 1 round, or 2 rounds if she exceeded the CMD by 5 to 9. If she exceeds the CMD by 10 or more, the effect is dispelled. A barbarian must have the <Link to="/ragepower/witch_hunter">witch hunter</Link> rage power and be at least 6th level before selecting this rage power.</p>
</>};
const _sunder_enchantment = {title: "Sunder Enchantment", jsx: <><p>While raging, whenever the barbarian succeeds at a sunder combat maneuver on a magical item, that item's magical abilities are suppressed for 1 round, plus 1 round for every 5 points by which her combat maneuver check exceeded the target's CMD. A barbarian must have the <Link to="/ragepower/spell_sunder">spell sunder</Link> rage power and be at least 8th level before selecting this rage power.</p>
</>};
const _surprise_accuracy = {title: "Surprise Accuracy", jsx: <><p>The barbarian gains a +1 morale bonus on one attack roll. This bonus increases by +1 for every 4 levels the barbarian has attained. This power is used as a swift action before the roll to hit is made. This power can only be used once per rage.</p>
</>};
const _deadly_accuracy = {title: "Deadly Accuracy", jsx: <><p>If the barbarian scores a critical threat when using her surprise accuracy rage power, she applies double the surprise accuracy bonus when rolling to confirm the critical. A barbarian must have the <Link to="/ragepower/surprise_accuracy">surprise accuracy</Link> rage power and be at least 4th level before selecting this rage power.</p>
</>};
const _lethal_accuracy = {title: "Lethal Accuracy", jsx: <><p>When using her surprise accuracy rage power, the barbarian's critical multiplier for damage increases by 1 (a &times;2 multiplier becomes &times;3, a 19-20/&times;2 multiplier becomes 19-20/&times;3, a &times;3 multiplier becomes &times;4, and a &times;4 multiplier becomes &times;5). A barbarian must have the <Link to="/ragepower/surprise_accuracy">surprise accuracy</Link> and <Link to="/ragepower/deadly_accuracy">deadly accuracy</Link> rage powers and be 16th level before selecting this rage power.</p>
</>};
const _sharpened_accuracy = {title: "Sharpened Accuracy", jsx: <><p>When using her surprise accuracy rage power, the barbarian ignores the miss chance for <Link to="/rule/concealment">concealment</Link> and treats total concealment as concealment. She also ignores cover penalties except those from total cover. A barbarian must have the <Link to="/ragepower/surprise_accuracy">surprise accuracy</Link> rage power and be at least 8th level before selecting this rage power.</p>
</>};
const _swift_foot = {title: "Swift Foot", jsx: <><p>The barbarian gains a 5-foot enhancement bonus to her speed. This increase is always active while the barbarian is raging. A barbarian can select this rage power up to three times. Its effects stack.</p>
</>};
const _sprint = {title: "Sprint", jsx: <><p>Once per rage, the barbarian can use a single full-round run action to move up to 6 times her speed or a single full-round charge action to move up to 3 times her speed. A barbarian must have the <Link to="/ragepower/swift_foot">swift foot</Link> rage power and be at least 4th level before selecting this rage power.</p>
</>};
const _two_fanged_pounce = {title: "Two-Fanged Pounce", jsx: <><p>If the barbarian is wielding a pair of <Link to="/eq-weapon/dagger">daggers</Link>, <Link to="/eq-weapon/kukri">kukris</Link>, or <Link to="/eq-weapon/punching_dagger">punching daggers</Link>, she can attack once with each of the two weapons when she charges. If she does, she loses the bonus on attack rolls for charging and takes an additional -2 penalty to her AC, and she applies <Link to="/misc/precision_damage">precision damage</Link> or effects that occur on a hit only once, even if she hits with both attacks.</p>
</>};
const _unexpected_strike = {title: "Unexpected Strike", jsx: <><p>The barbarian can make an attack of opportunity against a foe that moves into any square threatened by the barbarian, regardless of whether or not that movement would normally provoke an attack of opportunity. This power can only be used once per rage. A barbarian must be at least 8th level before selecting this power.</p>
</>};
const _unrestrained_rage = {title: "Unrestrained Rage", jsx: <><p>While raging, the barbarian is immune to paralysis. If the barbarian is targeted by an effect that would cause her to become <Link to="/rule/paralyzed">paralyzed</Link>, she can enter a rage as an immediate action, as long as she still has rounds of rage remaining. A barbarian must be at least 12th level to select this rage power.</p>
</>};
const _water_sense = {title: "Water Sense", jsx: <><p>The barbarian's senses are no longer fooled by the rippling surface and confounding reflections seen in water that is being used as <Link to="/rule/cover">cover</Link> by her foes. While the barbarian is raging and on land, opponents in the water gain only partial cover from her attacks, instead of improved cover. In addition, while on land and targeting an opponent in water, she takes only a -1 penalty on attacks with ranged weapons (including thrown weapons) for every 5 feet of water they pass through (instead of the usual -2 penalty for every 5 feet of water).</p>
</>};
const _winter_rage = {title: "Winter Rage", jsx: <><p>As a standard action, the barbarian can bellow a 20-foot cone of frigid, snowy air. Until the beginning of the barbarian's next turn, creatures moving through the cone move at half speed. A barbarian can have only one season-themed rage power, choosing between <Link to="/ragepower/spring_rage">spring</Link>, <Link to="/ragepower/summer_rage">summer</Link>, <Link to="/ragepower/autumn_rage">autumn</Link>, or winter rage.</p>
</>};
const _aryzuls_curse = {title: "Aryzul's Curse", jsx: <><p>When raging, the barbarian emanates a 5-foot-radius aura of radioactivity. Each round that another creature begins its turn within this aura, it takes a cumulative -2 penalty to Strength (Fortitude negates, DC = 10 + 1/2 the barbarian's level + her Constitution modifier) for the duration of the rage. A creature's Strength penalty from this ability cannot exceed the barbarian's class level. At 12th level, the barbarian can choose to create a 10-foot-radius aura of radioactivity when she begins her rage.</p>
<p><strong>Elemental Power:</strong> You must be at least 6th level to take this power, and you can only use one elemental rage power at a time. An <Link to="/class/unchained_barbarian">unchained barbarian</Link> can take this if they have the <Link to="/ragepower/elemental_stance">elemental stance</Link> stance rage power, and must adopt that stance to use this power. A barbarian or <Link to="/class/skald">skald</Link> must have the <Link to="/ragepower/lesser_elemental_rage">lesser elemental rage</Link> or <Link to="/ragepower/lesser_elemental_blood">lesser elemental blood</Link> rage power.</p>
</>};
const _hshurhas_veil = {title: "Hshurha's Veil", jsx: <><p>When raging, the barbarian can use Stealth, and she gains a bonus equal to 1/2 her barbarian level on Stealth checks plus the benefits of <Link to="/rule/concealment">concealment</Link> against ranged attacks and attacks of opportunity.</p>
<p><strong>Elemental Power:</strong> You must be at least 6th level to take this power, and you can only use one elemental rage power at a time. An <Link to="/class/unchained_barbarian">unchained barbarian</Link> can take this if they have the <Link to="/ragepower/elemental_stance">elemental stance</Link> stance rage power, and must adopt that stance to use this power. A barbarian or <Link to="/class/skald">skald</Link> must have the <Link to="/ragepower/lesser_elemental_rage">lesser elemental rage</Link> or <Link to="/ragepower/lesser_elemental_blood">lesser elemental blood</Link> rage power.</p>
</>};
const _kelizandris_tide = {title: "Kelizandri's Tide", jsx: <><p>When the barbarian rages, enemies find it difficult to escape the vortex of her fury. As a full-round action while raging, the barbarian can attempt a single combat maneuver check against each creature within 10 feet of her. If her roll equals or exceeds a creature's CMD, she moves that creature 5 feet closer to her. Once per day after attempting this maneuver, she can attack each adjacent creature as a free action as if using the <Link to="/feat/whirlwind_attack">Whirlwind Attack</Link> feat. If she has the Whirlwind Attack feat, she can also use it as a free action in this way one additional time per day.</p>
<p><strong>Elemental Power:</strong> You must be at least 6th level to take this power, and you can only use one elemental rage power at a time. An <Link to="/class/unchained_barbarian">unchained barbarian</Link> can take this if they have the <Link to="/ragepower/elemental_stance">elemental stance</Link> stance rage power, and must adopt that stance to use this power. A barbarian or <Link to="/class/skald">skald</Link> must have the <Link to="/ragepower/lesser_elemental_rage">lesser elemental rage</Link> or <Link to="/ragepower/lesser_elemental_blood">lesser elemental blood</Link> rage power.</p>
</>};
const _ymeris_pyre = {title: "Ymeri's Pyre", jsx: <><p>The barbarian visibly burns with an inner flame that consumes all impurities affecting her. Each round that the barbarian rages reduces the duration of negative spells and effects inflicted upon her as if 2 rounds had passed; this has no effect on the duration of such effects against other creatures. Once per day, the barbarian can expend 5 rounds of rage to attempt a new saving throw against each non-permanent effect currently affecting her. Each successful saving throw ends the related effect, and she can choose not to make a save against an effect.</p>
<p><strong>Elemental Power:</strong> You must be at least 6th level to take this power, and you can only use one elemental rage power at a time. An <Link to="/class/unchained_barbarian">unchained barbarian</Link> can take this if they have the <Link to="/ragepower/elemental_stance">elemental stance</Link> stance rage power, and must adopt that stance to use this power. A barbarian or <Link to="/class/skald">skald</Link> must have the <Link to="/ragepower/lesser_elemental_rage">lesser elemental rage</Link> or <Link to="/ragepower/lesser_elemental_blood">lesser elemental blood</Link> rage power.</p>
</>};
const _lesser_ancestor_totem = {title: "Lesser Ancestor Totem", jsx: <><p>When she enters a rage, the barbarian selects a skill of her choice, which must be one she can use while raging, such as Climb or Intimidate. While raging, she gains a +2 insight bonus to the chosen skill.</p>
<p><strong>Totem</strong> rage powers are only available to barbarians taking the <Link to="/arc-barbarian/totem_warrior">Totem Warrior</Link> archetype. A barbarian cannot select from more than one group of totem rage powers; for example, a barbarian who selects a <em>beast</em> totem rage power cannot later choose to gain any of the <em>dragon</em> totem rage powers (any rage power with "dragon totem" in its title).</p>
</>};
const _ancestor_totem = {title: "Ancestor Totem", jsx: <><p>The barbarian's insight bonus to her chosen skill increases to +4. The barbarian can now select any skill to receive this bonus, even a Charisma-, Dexterity-, or Intelligence-based skill or a skill that requires patience or concentration; if she selects such a skill, she can use it even while raging. A barbarian must have the <Link to="/ragepower/lesser_ancestor_totem">lesser ancestor totem</Link> rage power and be at least 6th level to select this rage power.</p>
</>};
const _greater_ancestor_totem = {title: "Greater Ancestor Totem", jsx: <><p>The barbarian's insight bonus to her chosen skill increases to +6. Once per rage, she can spend one round of rage as an immediate action to reroll a skill check in the chosen skill. She must take the result of the second roll, even if it is lower. A barbarian must have the <Link to="/ragepower/ancestor_totem">ancestor totem</Link> rage power and be at least 10th level to select this rage power.</p>
</>};
const _lesser_atavism_totem = {title: "Lesser Atavism Totem", jsx: <><p>The barbarian gains a bite attack; if she already has a bite attack, it deals damage as if the barbarian were one size larger.</p>
<p><strong>Totem</strong> rage powers are only available to barbarians taking the <Link to="/arc-barbarian/totem_warrior">Totem Warrior</Link> archetype. A barbarian cannot select from more than one group of totem rage powers; for example, a barbarian who selects a <em>beast</em> totem rage power cannot later choose to gain any of the <em>dragon</em> totem rage powers (any rage power with "dragon totem" in its title).</p>
</>};
const _atavism_totem = {title: "Atavism Totem", topLink: ["Totem Warrior","arc-barbarian/totem_warrior"], jsx: <><p>The barbarian gains <Link to="/umr/ferocity">ferocity</Link>. A barbarian must be at least 6th level and have the <Link to="/ragepower/lesser_atavism_totem">lesser atavism totem</Link> to select this rage power.</p>
</>};
const _greater_atavism_totem = {title: "Greater Atavism Totem", topLink: ["Totem Warrior","arc-barbarian/totem_warrior"], jsx: <><p>The barbarian gains <Link to="/umr/trample">trample</Link>. She must be at least 10th level and have the <Link to="/ragepower/atavism_totem">atavism totem</Link> to select this rage power.</p>
</>};
